import com.pinterest.ktlint.test.KtLintAssertThat
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.EOL_CHAR
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.MAX_LINE_LENGTH_MARKER
import org.junit.jupiter.api.Test

internal class PropertyWrappingRuleTestNew {
    private val propertyWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { PropertyWrappingRule() }

    @Test
    fun `Given that the call expression value does not fit on the same line then wrap before it with correct indentation`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                                                          $EOL_CHAR
            private val deferredMessageQueueSubscription = DeferredMessageQueueSubscription(uri = ServiceBusUri("deferredQueueTestUri"))
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                                                                          $EOL_CHAR
            private val deferredMessageQueueSubscription =
                DeferredMessageQueueSubscription(uri = ServiceBusUri("deferredQueueTestUri"))
            """.trimIndent()
        propertyWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { IndentationRule() }
            .hasLintViolation(2, 49, "Missing newline before \"DeferredMessageQueueSubscription(uri = ServiceBusUri(\"deferredQueueTestUri\"))\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given that the call expression value does not fit on the same line and property is indented then wrap before it with correct indentation`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                                                          $EOL_CHAR
            class Foo {
                private val deferredMessageQueueSubscription = DeferredMessageQueueSubscription(uri = ServiceBusUri("deferredQueueTestUri"))
            }
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                                                                          $EOL_CHAR
            class Foo {
                private val deferredMessageQueueSubscription =
                    DeferredMessageQueueSubscription(uri = ServiceBusUri("deferredQueueTestUri"))
            }
            """.trimIndent()
        propertyWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { IndentationRule() }
            .hasLintViolation(3, 53, "Missing newline before \"DeferredMessageQueueSubscription(uri = ServiceBusUri(\"deferredQueueTestUri\"))\"")
            .isFormattedAs(formattedCode)
    }
}
"}

